const rows = $input.first().json.churn_rows;

if (!rows || rows.length === 0) {
  return [{ json: { message: ':white_check_mark: *Daily Churn Report -- Last 30 Days*\n\nNo churned accounts found in the last 30 days.' } }];
}

const lines = rows.map(function(r) {
  const name = r.account_name || 'Unknown';
  const date = r.churn_date || 'N/A';
  const mrr = r.avg_mrr != null ? '$' + r.avg_mrr : 'N/A';
  const type = r.churn_type || 'N/A';
  const reason = r.churn_reason || 'N/A';
  const csm = r.csm || 'N/A';
  const owner = r.sf_account_owner || 'N/A';
  const segment = r.account_segmentation || 'N/A';
  const geo = r.geo_area || 'N/A';
  return '*' + name + '* | ' + date + ' | MRR: ' + mrr + ' | ' + type + ' | ' + reason + ' | CSM: ' + csm + ' | SF Owner: ' + owner + ' | ' + segment + ' | ' + geo;
});

const today = new Date().toISOString().slice(0, 10);
const header = ':rotating_light: *Daily Churn Report -- Last 30 Days* (' + today + ')';
const body = lines.join('\n');
const footer = '_Total accounts churned: ' + rows.length + '_';

return [{ json: { message: header + '\n\n' + body + '\n\n' + footer } }];
